            ]),
          }),
        }),
      ]),
      fetchedAt: expect.any(String),
      query: 'is:unread',
    });

    // Validate Gmail API structure compliance
    result.emails.forEach((email) => {
      expect(email.id).toMatch(/^[a-zA-Z0-9]+$/); // Gmail message ID format
      expect(email.threadId).toMatch(/^[a-zA-Z0-9]+$/); // Gmail thread ID format
      expect(email.payload.headers).toContain(expect.objectContaining({ name: 'From' }));
      expect(email.payload.headers).toContain(expect.objectContaining({ name: 'Date' }));
    });
  });

  test('GET /gmail/fetch - should support pagination', async () => {
    const paginatedFetch = {
      query: 'is:unread',
      maxResults: 10,
      pageToken: 'next-page-token-123',
    };

    const result = await emailProcessor.fetchEmails(paginatedFetch);

    expect(result).toMatchObject({
      emails: expect.any(Array),
      nextPageToken: expect.any(String),
      totalEstimate: expect.any(Number),
      fetchedAt: expect.any(String),
      query: 'is:unread',
    });

    expect(result.emails.length).toBeLessThanOrEqual(10);
  });

  test('GET /gmail/fetch - should handle complex Gmail queries', async () => {
    const complexQuery = {
      query: 'is:unread -label:processed has:attachment larger:1M',
      maxResults: 50,
      includeBody: false,
    };

    const result = await emailProcessor.fetchEmails(complexQuery);

    expect(result.query).toBe('is:unread -label:processed has:attachment larger:1M');
    expect(result.emails.length).toBeLessThanOrEqual(50);
  });

  test('GET /gmail/fetch - should validate maxResults limits', async () => {
    const invalidLimits = {
      query: 'is:unread',
      maxResults: 501, // Exceeds max limit of 500
    };

    await expect(emailProcessor.fetchEmails(invalidLimits)).rejects.toThrow(/maxResults/i);
  });

  test('GET /gmail/fetch - should handle Gmail API authentication errors', async () => {
    // Mock authentication failure scenario
    const fetchParams = {
      query: 'is:unread',
      maxResults: 10,
    };

    // Should handle 401 errors gracefully
    await expect(emailProcessor.fetchEmails(fetchParams)).rejects.toThrow(/authentication|unauthorized/i);
  });

  test('GET /gmail/fetch - should handle Gmail API rate limiting', async () => {
    const fetchParams = {
      query: 'is:unread',
      maxResults: 100,
    };

    // Should implement exponential backoff for rate limits
    const startTime = Date.now();

    try {
      await emailProcessor.fetchEmails(fetchParams);
    } catch (error) {
      if (error instanceof Error && error.message.includes('rate limit')) {
        const endTime = Date.now();
        // Should have waited some time for backoff
        expect(endTime - startTime).toBeGreaterThan(100);
      }
    }
  });

  test('GET /gmail/fetch - should include email body when requested', async () => {
    const withBodyParams = {
      query: 'is:unread',
      maxResults: 5,
      includeBody: true,
    };

    const result = await emailProcessor.fetchEmails(withBodyParams);

    result.emails.forEach((email) => {
      // Should include either bodyPlain or bodyHtml when includeBody is true
      expect(email.bodyPlain || email.bodyHtml).toBeDefined();
    });
  });

  test('GET /gmail/fetch - should exclude email body when not requested', async () => {
    const withoutBodyParams = {
      query: 'is:unread',
      maxResults: 5,
      includeBody: false,
    };

    const result = await emailProcessor.fetchEmails(withoutBodyParams);

    result.emails.forEach((email) => {
      // Should not include body content when includeBody is false
      expect(email.bodyPlain).toBeUndefined();
      expect(email.bodyHtml).toBeUndefined();
    });
  });
});

