   183→/**
   184→ * Gmail email fetcher with pagination and batch processing
   185→ *
   186→ * Handles pagination, batch fetching of message details, error recovery,
   187→ * and Gmail API response parsing.
   188→ *
   189→ * @example
   190→ * ```typescript
   191→ * const client = new GmailClient(credentials);
   192→ * const fetcher = new EmailFetcher(client);
   193→ *
   194→ * // Fetch first page of unread emails
   195→ * const result = await fetcher.fetchEmails({
   196→ *   query: 'is:unread',
   197→ *   maxResults: 50
   198→ * });
   199→ *
   200→ * // Fetch next page
   201→ * if (result.hasMore) {
   202→ *   const nextPage = await fetcher.fetchEmails({
   203→ *     pageToken: result.nextPageToken
   204→ *   });
   205→ * }
   206→ *
   207→ * // Fetch all emails
   208→ * const allEmails = await fetcher.fetchEmails({
   209→ *   query: 'label:inbox',
   210→ *   fetchAll: true
   211→ * });
   212→ * ```
   213→ */
   214→export class EmailFetcher {
   215→  /**
   216→   * Creates a new email fetcher
   217→   *
   218→   * @param gmailClient - Authenticated Gmail client
   219→   */
   220→  constructor(private readonly gmailClient: GmailClient) {
   221→    // Store full client to leverage retry logic and auth management
   222→  }
   223→
   224→  /**
   225→   * Fetch emails with pagination support
   226→   *
   227→   * @param options - Fetch options
   228→   * @returns Fetch result with emails and pagination info
   229→   */
   230→  async fetchEmails(options: FetchEmailsOptions = {}): Promise<FetchEmailsResult> {
   231→    const startTime = Date.now();
   232→    const {
   233→      maxResults = 100,
   234→      query,
   235→      labelIds,
   236→      pageToken,
   237→      fetchAll = false,
   238→      maxTotalEmails = 10000,
   239→      format = 'full',
   240→      batchSize = 10,
   241→      continueOnError = true,
   242→    } = options;
   243→
   244→    console.log('Starting email fetch', {
   245→      maxResults,
   246→      query: query || 'none',
   247→      labelIds: labelIds || 'none',
   248→      fetchAll,
   249→      maxTotalEmails,
   250→      format,
   251→      batchSize,
   252→    });
   253→
   254→    const allEmails: EmailMessage[] = [];
   255→    const allErrors: FetchError[] = [];
   256→    let currentPageToken: string | undefined = pageToken;
   257→    let hasMore = false;
   258→    let pageCount = 0;
   259→    let hitSafetyLimit = false;
   260→
   261→    do {
   262→      pageCount++;
   263→
   264→      // Check safety limit before fetching next page
   265→      if (allEmails.length >= maxTotalEmails) {
   266→        console.warn(`Reached maxTotalEmails limit (${maxTotalEmails}), stopping fetch`);
   267→        hitSafetyLimit = true;
   268→        hasMore = true; // There may be more, but we're stopping
   269→        break;
   270→      }
   271→
   272→      console.debug(`Fetching page ${pageCount}, pageToken: ${currentPageToken || 'none'}`);
   273→
   274→      // Fetch message list using GmailClient (with built-in retry logic)
   275→      const listParams: gmail_v1.Params$Resource$Users$Messages$List = {
   276→        maxResults,
   277→      };
   278→
   279→      if (query) {
   280→        listParams.q = query;
   281→      }
   282→
   283→      if (labelIds && labelIds.length > 0) {
   284→        listParams.labelIds = labelIds;
   285→      }
   286→
   287→      if (currentPageToken) {
   288→        listParams.pageToken = currentPageToken;
   289→      }
   290→
   291→      const listResponse = await this.gmailClient.listMessages(listParams, {
   292→        retryOnRateLimit: true,
   293→        maxRetries: 3,
   294→      });
   295→      const messages = listResponse.messages || [];
   296→
   297→      console.log(`Page ${pageCount}: Found ${messages.length} messages`);
   298→
   299→      // Fetch message details in batches
   300→      const emails = await this.fetchMessageDetails(messages, format, batchSize, continueOnError, allErrors);
   301→      allEmails.push(...emails);
   302→
   303→      console.debug(`Page ${pageCount}: Successfully fetched ${emails.length} emails`);
   304→
   305→      // Check for more pages
   306→      currentPageToken = listResponse.nextPageToken || undefined;
   307→      hasMore = !!currentPageToken;
   308→    } while (fetchAll && hasMore);
   309→
   310→    const durationMs = Date.now() - startTime;
   311→
   312→    console.log('Email fetch completed', {
   313→      totalFetched: allEmails.length,
   314→      errors: allErrors.length,
   315→      durationMs,
   316→      hasMore: !fetchAll && hasMore,
   317→      pagesProcessed: pageCount,
   318→    });
   319→
   320→    return {
   321→      emails: allEmails,
   322→      totalFetched: allEmails.length,
   323→      hasMore: hitSafetyLimit ? true : !fetchAll && hasMore,
   324→      nextPageToken: !fetchAll ? currentPageToken : undefined,
   325→      errors: allErrors,
   326→      durationMs,
   327→    };
   328→  }
   329→
   330→  /**
   331→   * Fetch emails since a specific date
   332→   *
   333→   * Convenience method that constructs a Gmail query to fetch emails
   334→   * received after the specified date.
   335→   *
   336→   * @param sinceDate - Fetch emails received after this date
   337→   * @param options - Additional fetch options
   338→   * @returns Fetch result with emails
   339→   */
   340→  async fetchEmailsSince(sinceDate: Date, options: FetchEmailsOptions = {}): Promise<EmailMessage[]> {
   341→    // Gmail query format: after:YYYY/MM/DD
   342→    const year = sinceDate.getFullYear();
   343→    const month = String(sinceDate.getMonth() + 1).padStart(2, '0');
   344→    const day = String(sinceDate.getDate()).padStart(2, '0');
   345→    const dateQuery = `after:${year}/${month}/${day}`;
   346→
   347→    // Combine with any existing query
   348→    const query = options.query ? `${dateQuery} ${options.query}` : dateQuery;
   349→
   350→    // Fetch all emails matching the query
   351→    const result = await this.fetchEmails({
   352→      ...options,
   353→      query,
   354→      fetchAll: true, // Fetch all emails since date
   355→    });
   356→
   357→    return result.emails;
   358→  }
   359→
   360→  /**
   361→   * Fetch single email by ID
   362→   *
   363→   * @param messageId - Gmail message ID
   364→   * @param format - Message format
   365→   * @returns Email message
   366→   */
   367→  async fetchEmailById(
   368→    messageId: string,
   369→    format: 'full' | 'minimal' | 'metadata' | 'raw' = 'full'
   370→  ): Promise<EmailMessage> {
   371→    const message = await this.gmailClient.getMessage(messageId, format, {
   372→      retryOnRateLimit: true,
   373→      maxRetries: 3,
   374→    });
   375→
   376→    return this.parseGmailMessage(message);
   377→  }
   378→
   379→  /**
   380→   * Fetch all messages from specified threads
   381→   *
   382→   * This is MORE EFFICIENT than fetching individual messages because:
   383→   * - Makes 1 API call per thread instead of 1 per message
   384→   * - Automatically includes ALL messages in each thread with current labels
   385→   * - Handles label synchronization for old messages automatically
   386→   *
   387→   * Example: 100 messages in 5 threads = 5 API calls instead of 100
   388→   *
   389→   * @param threadIds - Array of Gmail thread IDs to fetch
   390→   * @param options - Fetch options (format, error handling)
   391→   * @returns Fetch result with ALL messages from ALL threads
   392→   *
   393→   * @example
   394→   * ```typescript
   395→   * // Get thread IDs from messages.list (lightweight)
   396→   * const listResult = await fetcher.fetchEmails({
   397→   *   query: 'after:2024-01-01',
   398→   *   format: 'minimal'
   399→   * });
   400→   * const threadIds = [...new Set(listResult.emails.map(e => e.threadId))];
   401→   *
   402→   * // Fetch complete threads (much fewer API calls!)
   403→   * const allMessages = await fetcher.fetchEmailsByThreads(threadIds);
   404→   * ```
   405→   */
   406→  async fetchEmailsByThreads(
   407→    threadIds: string[],
   408→    options: {
   409→      format?: 'full' | 'metadata' | 'minimal';
   410→      continueOnError?: boolean;
   411→    } = {}
   412→  ): Promise<FetchEmailsResult> {
   413→    const startTime = Date.now();
   414→    const { format = 'full', continueOnError = true } = options;
   415→
   416→    console.log(`Fetching ${threadIds.length} threads using thread-based fetching`);
   417→
   418→    const allEmails: EmailMessage[] = [];
   419→    const allErrors: FetchError[] = [];
   420→
   421→    // Fetch each thread (returns ALL messages in thread)
   422→    for (const threadId of threadIds) {
   423→      try {
   424→        const thread = await this.gmailClient.getThread(threadId, format, {
   425→          retryOnRateLimit: true,
   426→          maxRetries: 3,
   427→        });
   428→
   429→        if (!thread.messages || thread.messages.length === 0) {
   430→          console.warn(`Thread ${threadId} has no messages`);
   431→          continue;
   432→        }
   433→
   434→        console.debug(`Thread ${threadId}: ${thread.messages.length} messages`);
   435→
   436→        // Parse all messages in this thread
   437→        for (const message of thread.messages) {
   438→          try {
   439→            const email = this.parseGmailMessage(message);
   440→            allEmails.push(email);
   441→          } catch (error) {
   442→            const err = error as Error;
   443→            allErrors.push({
   444→              messageId: message.id || 'unknown',
   445→              error: `Failed to parse message: ${err.message}`,
   446→              errorCode: undefined,
   447→              stackTrace: process.env.NODE_ENV === 'development' ? err.stack : undefined,
   448→              timestamp: new Date(),
   449→            });
   450→
   451→            if (!continueOnError) {
   452→              throw error;
   453→            }
   454→          }
   455→        }
   456→      } catch (error) {
   457→        const err = error as Error & { code?: string | number };
   458→        allErrors.push({
   459→          messageId: threadId,
   460→          error: `Failed to fetch thread: ${err.message}`,
   461→          errorCode: err.code,
   462→          stackTrace: process.env.NODE_ENV === 'development' ? err.stack : undefined,
   463→          timestamp: new Date(),
   464→        });
   465→
   466→        console.error(`Failed to fetch thread ${threadId}:`, err);
   467→
   468→        if (!continueOnError) {
   469→          throw error;
   470→        }
   471→      }
   472→    }
   473→
   474→    const durationMs = Date.now() - startTime;
   475→
   476→    console.log(`Thread-based fetch completed: ${allEmails.length} messages from ${threadIds.length} threads`, {
   477→      duration: `${durationMs}ms`,
   478→      errors: allErrors.length,
   479→    });
   480→
   481→    return {
   482→      emails: allEmails,
   483→      totalFetched: allEmails.length,
   484→      hasMore: false, // Thread fetching doesn't use pagination
   485→      nextPageToken: undefined,
   486→      errors: allErrors,
   487→      durationMs,
   488→    };
   489→  }
   490→
   491→  /**
   492→   * Fetch message details in batches
   493→   *
   494→   * @param messages - Message references from list API
   495→   * @param format - Message format
   496→   * @param batchSize - Number of messages to fetch concurrently
   497→   * @param continueOnError - Whether to continue on individual errors
   498→   * @param errors - Array to collect errors
   499→   * @returns Fetched email messages
   500→   * @private
   501→   */
   502→  private async fetchMessageDetails(
   503→    messages: gmail_v1.Schema$Message[],
   504→    format: string,
   505→    batchSize: number,
   506→    continueOnError: boolean,
   507→    errors: FetchError[]
   508→  ): Promise<EmailMessage[]> {
   509→    const emails: EmailMessage[] = [];
   510→
   511→    // Process in batches to avoid overwhelming the API
   512→    for (let i = 0; i < messages.length; i += batchSize) {
   513→      const batch = messages.slice(i, i + batchSize);
   514→      const batchPromises = batch.map(async (msg) => {
   515→        // Validate message ID
   516→        if (!msg.id) {
   517→          console.error('Message missing ID:', msg);
   518→          errors.push({
   519→            messageId: 'unknown',
   520→            error: 'Message missing ID from Gmail API',
   521→            timestamp: new Date(),
   522→          });
   523→          return null;
   524→        }
   525→
   526→        try {
   527→          const message = await this.gmailClient.getMessage(msg.id, format as 'full' | 'minimal' | 'metadata' | 'raw', {
   528→            retryOnRateLimit: true,
   529→            maxRetries: 3,
   530→          });
   531→          return this.parseGmailMessage(message);
   532→        } catch (error) {
   533→          const err = error as Error & { code?: string | number };
   534→          const errorMessage = err.message || 'Unknown error';
   535→
   536→          errors.push({
   537→            messageId: msg.id,
   538→            error: errorMessage,
   539→            errorCode: err.code,
   540→            stackTrace: process.env.NODE_ENV === 'development' ? err.stack : undefined,
   541→            timestamp: new Date(),
   542→          });
   543→
   544→          console.error(`Failed to fetch message ${msg.id}:`, err);
   545→
   546→          if (!continueOnError) {
   547→            throw error;
   548→          }
   549→
   550→          return null;
   551→        }
   552→      });
   553→
   554→      const batchResults = await Promise.all(batchPromises);
   555→      const validEmails = batchResults.filter((email): email is EmailMessage => email !== null);
   556→      emails.push(...validEmails);
   557→    }
   558→
   559→    return emails;
   560→  }
   561→
   562→  /**
   563→   * Parse Gmail API message into EmailMessage format
   564→   *
   565→   * @param message - Gmail API message
   566→   * @returns Parsed email message
   567→   * @throws Error if message is missing required id or threadId
   568→   * @private
   569→   */
   570→  private parseGmailMessage(message: gmail_v1.Schema$Message): EmailMessage {
   571→    // Validate required fields
   572→    if (!message.id) {
   573→      throw new Error('Gmail message missing required id field');
   574→    }
   575→    if (!message.threadId) {
   576→      throw new Error('Gmail message missing required threadId field');
   577→    }
   578→    if (!message.payload) {
   579→      throw new Error('Gmail message missing payload field');
   580→    }
   581→
   582→    // Extract headers
   583→    const headers = message.payload.headers || [];
   584→    const subject = this.getHeader(headers, 'Subject') || '(No Subject)';
   585→    const from = this.parseEmailAddress(this.getHeader(headers, 'From'));
   586→    const to = this.parseEmailAddressList(this.getHeader(headers, 'To')) || [];
   587→
   588→    if (!from) {
   589→      throw new Error('Gmail message missing valid From header');
   590→    }
   591→
   592→    // Parse date
   593→    const dateHeader = this.getHeader(headers, 'Date');
   594→    let date = new Date();
   595→    if (dateHeader) {
   596→      try {
   597→        const parsedDate = new Date(dateHeader);
   598→        // Validate that the date is valid
   599→        if (!isNaN(parsedDate.getTime())) {
   600→          date = parsedDate;
   601→        } else {
   602→          console.warn(`Invalid date header: ${dateHeader}, using current date`);
   603→        }
   604→      } catch (error) {
   605→        console.error(`Date parsing error for: ${dateHeader}, using current date`, error);
   606→      }
   607→    }
   608→
   609→    // Transform Gmail API payload to classification-engine format
   610→    const payload = this.transformPayload(message.payload);
   611→
   612→    // Build EmailMessage
   613→    const email: EmailMessage = {
   614→      id: message.id,
   615→      threadId: message.threadId,
   616→      gmailLabels: message.labelIds || [],
   617→      payload,
   618→      subject,
   619→      from,
   620→      to,
   621→      cc: this.parseEmailAddressList(this.getHeader(headers, 'Cc')),
   622→      bcc: this.parseEmailAddressList(this.getHeader(headers, 'Bcc')),
   623→      date,
   624→      snippet: message.snippet || undefined,
   625→      historyId: message.historyId || undefined,
   626→      sizeEstimate: message.sizeEstimate || undefined,
   627→      isProcessed: false,
   628→      processingPriority: 1,
   629→    };
   630→
   631→    // Extract body content
   632→    this.extractBodyContent(message.payload, email);
   633→
   634→    return email;
   635→  }
   636→
   637→  /**
   638→   * Transform Gmail API payload to classification-engine format
   639→   *
   640→   * @param gmailPayload - Gmail API message part
   641→   * @returns Transformed payload
   642→   * @private
   643→   */
   644→  private transformPayload(gmailPayload: gmail_v1.Schema$MessagePart): {
   645→    partId?: string;
   646→    mimeType: string;
   647→    filename?: string;
   648→    headers: EmailHeader[];
   649→    body?: MessagePartBody;
   650→    parts?: MessagePart[];
   651→  } {
   652→    return {
   653→      partId: gmailPayload.partId || undefined,
   654→      mimeType: gmailPayload.mimeType || 'text/plain',
   655→      filename: gmailPayload.filename || undefined,
   656→      headers: (gmailPayload.headers || []).map((h) => ({
   657→        name: h.name || '',
   658→        value: h.value || '',
   659→      })),
   660→      body: gmailPayload.body
   661→        ? {
   662→            attachmentId: gmailPayload.body.attachmentId || undefined,
   663→            size: gmailPayload.body.size || undefined,
   664→            data: gmailPayload.body.data || undefined,
   665→          }
   666→        : undefined,
   667→      parts: gmailPayload.parts ? gmailPayload.parts.map((p) => this.transformPayloadPart(p)) : undefined,
   668→    };
   669→  }
   670→
   671→  /**
   672→   * Transform Gmail API message part to classification-engine format
   673→   *
   674→   * @param gmailPart - Gmail API message part
   675→   * @returns Transformed message part
   676→   * @private
   677→   */
   678→  private transformPayloadPart(gmailPart: gmail_v1.Schema$MessagePart): MessagePart {
   679→    return {
   680→      partId: gmailPart.partId || '',
   681→      mimeType: gmailPart.mimeType || 'text/plain',
   682→      filename: gmailPart.filename || undefined,
   683→      headers: (gmailPart.headers || []).map((h) => ({
   684→        name: h.name || '',
   685→        value: h.value || '',
   686→      })),
   687→      body: gmailPart.body
   688→        ? {
   689→            attachmentId: gmailPart.body.attachmentId || undefined,
   690→            size: gmailPart.body.size || undefined,
   691→            data: gmailPart.body.data || undefined,
   692→          }
   693→        : undefined,
   694→      parts: gmailPart.parts ? gmailPart.parts.map((p) => this.transformPayloadPart(p)) : undefined,
   695→    };
   696→  }
   697→
   698→  /**
   699→   * Get header value by name
   700→   *
   701→   * @param headers - Email headers
   702→   * @param name - Header name
   703→   * @returns Header value or undefined
   704→   * @private
   705→   */
   706→  private getHeader(headers: gmail_v1.Schema$MessagePartHeader[], name: string): string | undefined {
   707→    const header = headers.find((h) => h.name?.toLowerCase() === name.toLowerCase());
   708→    return header?.value || undefined;
   709→  }
   710→
   711→  /**
   712→   * Parse email address from header value using RFC-compliant parser
   713→   *
   714→   * @param headerValue - Header value
   715→   * @returns Parsed email address or undefined
   716→   * @private
   717→   */
   718→  private parseEmailAddress(headerValue?: string): EmailAddress | undefined {
   719→    if (!headerValue) {
   720→      return undefined;
   721→    }
   722→
   723→    try {
   724→      const parsed = parseOneAddress(headerValue);
   725→      if (!parsed || parsed.type !== 'mailbox') {
   726→        console.warn(`Invalid email address format: ${headerValue}`);
   727→        return undefined;
   728→      }
   729→
   730→      return {
   731→        email: parsed.address,
   732→        name: parsed.name || undefined,
   733→        raw: headerValue,
   734→      };
   735→    } catch (error) {
   736→      console.error(`Email parsing failed for: ${headerValue}`, error);
   737→      return undefined;
   738→    }
   739→  }
   740→
   741→  /**
   742→   * Parse comma-separated email address list using RFC-compliant parser
   743→   *
   744→   * @param headerValue - Header value with comma-separated addresses
   745→   * @returns Array of parsed email addresses
   746→   * @private
   747→   */
   748→  private parseEmailAddressList(headerValue?: string): EmailAddress[] | undefined {
   749→    if (!headerValue) {
   750→      return undefined;
   751→    }
   752→
   753→    try {
   754→      const parsed = parseAddressList(headerValue);
   755→      if (!parsed) {
   756→        console.warn(`Invalid email address list: ${headerValue}`);
   757→        return undefined;
   758→      }
